import { Text as PDFText } from '@react-pdf/renderer';
import type { Style } from '@react-pdf/types';
import { Fragment } from 'react';
import { usePdfxTheme, useSafeMemo } from '../lib/pdfx-theme-context';
import { Table, TableBody, TableCell, TableFooter, TableHeader, TableRow } from '../table/pdfx-table';
import { createCompactStyles, formatValue } from './pdfx-data-table.styles';
import type { DataTableProps } from './pdfx-data-table.types';

export function DataTable<T extends Record<string, unknown>>({
  columns,
  data,
  variant = 'grid',
  footer,
  stripe = false,
  size = 'default',
  noWrap = false,
  style,
}: DataTableProps<T>) {
  const theme = usePdfxTheme();
  const compact = useSafeMemo(() => createCompactStyles(theme), [theme]);
  const isCompact = size === 'compact';

  return (
    <Table variant={variant} zebraStripe={stripe} noWrap={noWrap} style={style}>
      <TableHeader>
        <TableRow header>
          {columns.map((col) => (
            <TableCell
              key={col.key}
              header
              align={col.align ?? 'left'}
              width={col.width}
              style={isCompact ? compact.cell : undefined}
            >
              {isCompact ? (
                <PDFText
                  style={[compact.headerText, col.align ? ({ textAlign: col.align } as Style) : {}]}
                >
                  {col.header}
                </PDFText>
              ) : (
                col.header
              )}
            </TableCell>
          ))}
        </TableRow>
      </TableHeader>
      <TableBody>
        {data.map((row, i) => (
          // biome-ignore lint/suspicious/noArrayIndexKey: DataTable has no row id; order is stable for static data
          <Fragment key={i}>
            <TableRow>
              {columns.map((col) => {
                const value = row[col.key];
                const rendered = col.render ? col.render(value, row) : null;
                const text = rendered === null ? formatValue(value) : null;
                return (
                  <TableCell
                    key={col.key}
                    align={col.align ?? 'left'}
                    width={col.width}
                    style={isCompact ? compact.cell : undefined}
                  >
                    {isCompact ? (
                      rendered !== null ? (
                        rendered
                      ) : (
                        <PDFText
                          style={[
                            compact.text,
                            col.align ? ({ textAlign: col.align } as Style) : {},
                          ]}
                        >
                          {text}
                        </PDFText>
                      )
                    ) : rendered !== null ? (
                      rendered
                    ) : (
                      text
                    )}
                  </TableCell>
                );
              })}
            </TableRow>
          </Fragment>
        ))}
      </TableBody>
      {footer && (
        <TableFooter>
          <TableRow footer>
            {columns.map((col) => {
              const value = col.key in footer ? footer[col.key] : '';
              const rendered = col.renderFooter ? col.renderFooter(value) : null;
              const text = rendered === null ? formatValue(value) : null;
              return (
                <TableCell
                  key={col.key}
                  footer={!!value}
                  align={col.align ?? 'left'}
                  width={col.width}
                  style={isCompact ? compact.cell : undefined}
                >
                  {isCompact ? (
                    rendered !== null ? (
                      rendered
                    ) : (
                      <PDFText
                        style={[
                          value ? compact.footerText : compact.text,
                          col.align ? ({ textAlign: col.align } as Style) : {},
                        ]}
                      >
                        {text}
                      </PDFText>
                    )
                  ) : rendered !== null ? (
                    rendered
                  ) : (
                    text
                  )}
                </TableCell>
              );
            })}
          </TableRow>
        </TableFooter>
      )}
    </Table>
  );
}

import { StyleSheet } from '@react-pdf/renderer';
import { usePdfxTheme } from '../lib/pdfx-theme-context';
type PdfxTheme = ReturnType<typeof usePdfxTheme>;

/**
 * Creates compact-mode cell and text styles for the DataTable component.
 * Used when `size="compact"` to render denser rows with smaller font sizes.
 * @param t - The resolved PdfxTheme instance.
 */
export function createCompactStyles(t: PdfxTheme) {
  const { spacing, fontWeights, lineHeights } = t.primitives;
  return StyleSheet.create({
    cell: {
      paddingVertical: spacing[0.5],
      paddingHorizontal: spacing[2],
    },
    text: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.primitives.typography.xs,
      lineHeight: lineHeights.normal,
      color: t.colors.foreground,
    },
    headerText: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.primitives.typography.xs,
      lineHeight: lineHeights.normal,
      color: t.colors.foreground,
      fontWeight: fontWeights.semibold,
    },
    footerText: {
      fontFamily: t.typography.body.fontFamily,
      fontSize: t.primitives.typography.xs,
      lineHeight: lineHeights.normal,
      color: t.colors.foreground,
      fontWeight: fontWeights.semibold,
    },
  });
}

/**
 * Converts an arbitrary cell value to a display string.
 * Returns an empty string for null/undefined values.
 * @param value - The raw cell value to format.
 */
export function formatValue(value: unknown): string {
  if (value === null || value === undefined) return '';
  if (typeof value === 'number') return String(value);
  return String(value);
}

import type React from 'react';
import type { TableVariant } from '../table/pdfx-table.types';
import type { Style } from '@react-pdf/types';

/** DataTable row density size. */
export type DataTableSize = 'default' | 'compact';

/** Column definition for a DataTable. */
export interface DataTableColumn<T = Record<string, unknown>> {
  /** Key of the data row object to read the cell value from. */
  key: keyof T & string;
  /** Column header label. */
  header: string;
  /** Horizontal text alignment for both header and body cells. @default 'left' */
  align?: 'left' | 'center' | 'right';
  /** Fixed column width in PDF points or CSS-like string. Omit to let the column flex-grow. */
  width?: string | number;
  /** Custom renderer for body cells. Return `null` to fall back to the default value formatter. */
  render?: (value: unknown, row: T) => React.ReactNode;
  /** Custom renderer for the footer cell. Return `null` to fall back to the default value formatter. */
  renderFooter?: (value: unknown) => React.ReactNode;
}

export interface DataTableProps<T = Record<string, unknown>> {
  /** Custom styles to merge with component defaults */
  style?: Style;
  /** Column definitions — determines headers, keys, widths, and custom renderers. */
  columns: DataTableColumn<T>[];
  /** Row data array. Each object is rendered as one table row. */
  data: T[];
  /** Visual table style variant passed to the underlying `Table`. @default 'line' */
  variant?: TableVariant;
  /** Optional footer row values keyed by column key. */
  footer?: Partial<Record<keyof T & string, string | number>>;
  /** Apply alternating row background colors. @default false */
  stripe?: boolean;
  /** Row density — `compact` reduces cell padding and font size for data-dense layouts. @default 'default' */
  size?: DataTableSize;
  /** Prevent the entire table from splitting across PDF pages. Use for short tables that fit on one page. */
  noWrap?: boolean;
}
